/**
 * Shared mineral constants used across sim and UI layers.
 *
 * MINERAL_FIELDS — the 7 minerals stored in ECS components (MineralComposition, Inventory, Storage).
 * CORE_RESOURCES — the 4 resources surfaced to the HUD and sent via storageBuffer.
 */

/** All 7 mineral fields in ECS storage order. */
export const MINERAL_FIELDS = [
  'iron',
  'nickel',
  'cobalt',
  'platinum',
  'ice',
  'carbon',
  'silicate',
] as const;

export type MineralField = (typeof MINERAL_FIELDS)[number];

/** Core 4 resource keys used in the HUD display and storageBuffer worker→main message. */
export const CORE_RESOURCES = ['iron', 'carbon', 'silicon', 'water'] as const;

export type CoreResource = (typeof CORE_RESOURCES)[number];

/** Display names for the 4 core HUD resources. Import this instead of hard-coding labels. */
export const CORE_RESOURCE_LABELS: Record<CoreResource, string> = {
  iron: 'Iron',
  carbon: 'Carbon',
  silicon: 'Silicon',
  water: 'Water',
};

/** Call cb for every mineral field. */
export function forEachMineral(cb: (field: MineralField) => void): void {
  for (const f of MINERAL_FIELDS) cb(f);
}

/** Sum all mineral values in a record. */
export function sumMinerals(values: Record<MineralField, number>): number {
  let total = 0;
  for (const f of MINERAL_FIELDS) total += values[f];
  return total;
}
