/**
 * Shared buffer layout constants for sim → render transfer buffers.
 *
 * Both the robot buffer (Float32Array) and the asteroid buffer (Float64Array)
 * use a stride of 8. All consumer sites must import from here so that adding
 * or reordering a field produces a compile-time error at every callsite.
 */

// ─── Robot buffer ──────────────────────────────────────────────────────────
// Float32Array layout: [eid, x, y, z, rotation, typeEnum, stateEnum, energyPct]

export const ROBOT_STRIDE = 8;

export const ROBOT_OFF_EID = 0;
export const ROBOT_OFF_X = 1;
export const ROBOT_OFF_Y = 2;
export const ROBOT_OFF_Z = 3;
export const ROBOT_OFF_ROTATION = 4;
export const ROBOT_OFF_TYPE = 5;
export const ROBOT_OFF_STATE = 6;
export const ROBOT_OFF_ENERGY_PCT = 7;

// ─── Robot buffer accessors ────────────────────────────────────────────────
// Thin helpers to eliminate raw stride arithmetic at call sites.
// V8 inlines these; zero runtime cost.

export function robotCount(buffer: Float32Array): number {
  return buffer.length / ROBOT_STRIDE;
}

export function getRobotEid(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_EID];
}

export function getRobotX(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_X];
}

export function getRobotY(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_Y];
}

export function getRobotZ(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_Z];
}

export function getRobotRotation(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_ROTATION];
}

export function getRobotType(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_TYPE];
}

export function getRobotState(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_STATE];
}

export function getRobotEnergyPct(buffer: Float32Array, index: number): number {
  return buffer[index * ROBOT_STRIDE + ROBOT_OFF_ENERGY_PCT];
}

// ─── Asteroid buffer ───────────────────────────────────────────────────────
// Float64Array layout: [eid, x, y, z, radius, typeEnum, anomalyFlag, huskFlag, sizeTier, clusterFlag]

export const ASTEROID_STRIDE = 11;

export const ASTEROID_OFF_EID = 0;
export const ASTEROID_OFF_X = 1;
export const ASTEROID_OFF_Y = 2;
export const ASTEROID_OFF_Z = 3;
export const ASTEROID_OFF_RADIUS = 4;
export const ASTEROID_OFF_TYPE = 5;
export const ASTEROID_OFF_ANOMALY_FLAG = 6;
export const ASTEROID_OFF_HUSK_FLAG = 7;
export const ASTEROID_OFF_TIER = 8;
/** 1 if this asteroid is part of a transient rich cluster, 0 otherwise */
export const ASTEROID_OFF_CLUSTER_FLAG = 9;
/** Transit window factor 0..1 (1 = in optimal window, 0 = far side of belt) */
export const ASTEROID_OFF_TRANSIT_FACTOR = 10;

// ─── Threat buffer ────────────────────────────────────────────────────────
// Float32Array layout per active threat:
// [threatId, threatTypeEnum, factionId, originX, originY, originZ,
//  targetX, targetY, targetZ, progress]
//
// threatTypeEnum: 0=trajectory_interjection, 1=claim_jump, 2=mass_driver_threat, 3=signal_jam
// progress: 0.0 (just detected) → 1.0 (arrived)

export const THREAT_STRIDE = 10;

export const THREAT_OFF_ID = 0;
export const THREAT_OFF_TYPE = 1;
export const THREAT_OFF_FACTION_ID = 2;
export const THREAT_OFF_ORIGIN_X = 3;
export const THREAT_OFF_ORIGIN_Y = 4;
export const THREAT_OFF_ORIGIN_Z = 5;
export const THREAT_OFF_TARGET_X = 6;
export const THREAT_OFF_TARGET_Y = 7;
export const THREAT_OFF_TARGET_Z = 8;
export const THREAT_OFF_PROGRESS = 9;

export function threatCount(buffer: Float32Array): number {
  return buffer.length / THREAT_STRIDE;
}

export function getThreatId(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_ID];
}

export function getThreatType(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_TYPE];
}

export function getThreatFactionId(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_FACTION_ID];
}

export function getThreatOriginX(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_ORIGIN_X];
}

export function getThreatOriginY(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_ORIGIN_Y];
}

export function getThreatOriginZ(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_ORIGIN_Z];
}

export function getThreatTargetX(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_TARGET_X];
}

export function getThreatTargetY(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_TARGET_Y];
}

export function getThreatTargetZ(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_TARGET_Z];
}

export function getThreatProgress(buffer: Float32Array, index: number): number {
  return buffer[index * THREAT_STRIDE + THREAT_OFF_PROGRESS];
}

/** Map ThreatType string to buffer enum value */
export const THREAT_TYPE_ENUM: Record<string, number> = {
  trajectory_interjection: 0,
  claim_jump: 1,
  mass_driver_threat: 2,
  signal_jam: 3,
};
